class SQSWorker:
    """Secure SQS message worker with validation and allowlisted handlers."""

    def __init__(
        self,
        queue_url: str,
        region_name: str = "us-east-1",
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 300,
        max_retries: int = 3,
    ):
        if not queue_url or not isinstance(queue_url, str):
            raise ValueError("A valid queue_url is required")

        # Validate queue URL format to prevent SSRF
        if not re.match(r'^https://sqs\.[a-z0-9\-]+\.amazonaws\.com/\d{12}/[\w\-]+$', queue_url):
            raise ValueError("Invalid SQS queue URL format")

        self.queue_url = queue_url
        self.max_messages = min(max(1, max_messages), 10)  # SQS limit is 10
        self.wait_time_seconds = min(max(0, wait_time_seconds), 20)  # SQS limit is 20
        self.visibility_timeout = min(max(0, visibility_timeout), 43200)  # SQS limit is 12 hours
        self.max_retries = max_retries
        self._running = False

        # Initialize boto3 client - credentials from IAM role/environment, never hardcoded
        self.sqs_client = boto3.client("sqs", region_name=region_name)

        # Register handlers using explicit allowlist mapping
        self._handlers: Dict[str, MessageHandler] = {
            MessageType.SEND_EMAIL.value: SendEmailHandler(),
            MessageType.PROCESS_IMAGE.value: ProcessImageHandler(),
            MessageType.GENERATE_REPORT.value: GenerateReportHandler(),
            MessageType.SYNC_DATA.value: SyncDataHandler(),
            MessageType.CLEANUP.value: CleanupHandler(),
        }

        self._dead_letter_queue_url: Optional[str] = None

    def set_dead_letter_queue(self, dlq_url: str) -> None:
        """Set a dead letter queue for failed messages."""
        if not re.match(r'^https://sqs\.[a-z0-9\-]+\.amazonaws\.com/\d{12}/[\w\-]+$', dlq_url):
            raise ValueError("Invalid SQS DLQ URL format")
        self._dead_letter_queue_url = dlq_url

    def _get_handler(self, message_type: str) -> Optional[MessageHandler]:
        """Get handler from allowlisted registry only."""
        return self._handlers.get(message_type)

    def _process_message(self, message: Dict) -> ProcessingResult:
        """Process a single SQS message with full validation."""
        message_id = message.get("MessageId", "unknown")
        receipt_handle = message.get("ReceiptHandle")
        raw_body = message.get("Body", "")

        logger.info("Processing message", extra={"message_id": message_id})

        # Step 1: Validate and sanitize the message
        validation_result = InputValidator.validate_message(raw_body)
        if not validation_result.is_valid:
            logger.warning(
                "Message validation failed",
                extra={"message_id": message_id, "error": validation_result.error}
            )
            # Delete invalid messages to prevent reprocessing
            self._delete_message(receipt_handle)
            return ProcessingResult(
                success=False,
                message_id=message_id,
                message_type="unknown",
                error=f"Validation failed: {validation_result.error}"
            )

        sanitized = validation_result.sanitized_payload
        message_type = sanitized["message_type"]
        payload = sanitized["payload"]
        job_id = sanitized.get("job_id", message_id)

        # Step 2: Get handler from allowlist
        handler = self._get_handler(message_type)
        if handler is None:
            logger.error(
                "No handler registered for message type",
                extra={"message_id": message_id, "message_type": message_type}
            )
            self._delete_message(receipt_handle)
            return ProcessingResult(
                success=False,
                message_id=message_id,
                message_type=message_type,
                error="No handler for message type"
            )

        # Step 3: Execute handler
        try:
            result = handler.handle(payload, job_id=job_id)
            if result.success:
                self._delete_message(receipt_handle)
                logger.info(
                    "Message processed successfully",
                    extra={"message_id": message_id, "message_type": message_type}
                )
            else:
                logger.warning(
                    "Handler returned failure",
                    extra={"message_id": message_id, "message_type": message_type, "error": result.error}
                )
                # Let visibility timeout expire for retry, or send to DLQ
                self._handle_failed_message(message, result.error)
            return result

        except Exception as e:
            # Catch handler exceptions - log type only, not full details which may contain sensitive data
            logger.error(
                "Handler exception",
                extra={
                    "message_id": message_id,
                    "message_type": message_type,
                    "exception_type": type(e).__name__
                }
            )
            self._handle_failed_message(message, f"Handler exception: {type(e).__name__}")
            return ProcessingResult(
                success=False,
                message_id=message_id,
                message_type=message_type,
                error=f"Handler exception: {type(e).__name__}"
            )

    def _delete_message(self, receipt_handle: str) -> None:
        """Delete a message from the queue after successful processing."""
        if not receipt_handle:
            return
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
        except ClientError as e:
            logger.error(
                "Failed to delete message",
                extra={"error_code": e.response.get("Error", {}).get("Code", "Unknown")}
            )

    def _handle_failed_message(self, message: Dict, error: str) -> None:
        """Handle a failed message - optionally send to DLQ."""
        message_id = message.get("MessageId", "unknown")

        # Check approximate receive count for retry logic
        attributes = message.get("Attributes", {})
        receive_count = int(attributes.get("ApproximateReceiveCount", "0"))

        if receive_count >= self.max_retries and self._dead_letter_queue_url:
            logger.warning(
                "Max retries exceeded, sending to DLQ",
                extra={"message_id": message_id, "receive_count": receive_count}
            )
            try:
                self.sqs_client.send_message(
                    QueueUrl=self._dead_letter_queue_url,
                    MessageBody=json.dumps({
                        "original_message_id": message_id,
                        "error": error,
                        "receive_count": receive_count,
                    }),
                )
                # Delete from main queue after sending to DLQ
                self._delete_message(message.get("ReceiptHandle"))
            except ClientError as e:
                logger.error(
                    "Failed to send to DLQ",
                    extra={"error_code": e.response.get("Error", {}).get("Code", "Unknown")}
                )

    def poll_messages(self) -> list:
        """Poll messages from SQS with long polling."""
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=["ApproximateReceiveCount", "SentTimestamp"],
                MessageAttributeNames=["All"],
            )
            return response.get("Messages", [])
        except ClientError as e:
            error_code = e.response.get("Error", {}).get("Code", "Unknown")
            logger.error("Failed to receive messages", extra={"error_code": error_code})
            return []

    def run(self, poll_interval_on_empty: float = 1.0) -> None:
        """Main worker loop."""
        self._running = True
        logger.info("SQS Worker started", extra={"queue_url": self.queue_url})

        while self._running:
            try:
                messages = self.poll_messages()

                if not messages:
                    time.sleep(poll_interval_on_empty)
                    continue

                for message in messages:
                    if not self._running:
                        break
                    self._process_message(message)

            except KeyboardInterrupt:
                logger.info("Received shutdown signal")
                self.stop()
            except Exception as e:
                logger.error(
                    "Unexpected error in worker loop",
                    extra={"exception_type": type(e).__name__}
                )
                time.sleep(5)  # Back off on unexpected errors

        logger.info("SQS Worker stopped")

    def stop(self) -> None:
        """Gracefully stop the worker."""
        self._running = False


def create_worker_from_env() -> SQSWorker:
    """Create a worker from environment variables - no hardcoded secrets."""
    queue_url = os.environ.get("SQS_QUEUE_URL")
    if not queue_url:
        raise EnvironmentError("SQS_QUEUE_URL environment variable is required")

    region = os.environ.get("AWS_REGION", "us-east-1")
    max_messages = int(os.environ.get("SQS_MAX_MESSAGES", "10"))
    wait_time = int(os.environ.get("SQS_WAIT_TIME_SECONDS", "20"))
    visibility_timeout = int(os.environ.get("SQS_VISIBILITY_TIMEOUT", "300"))
    max_retries = int(os.environ.get("SQS_MAX_RETRIES", "3"))

    worker = SQSWorker(
        queue_url=queue_url,
        region_name=region,
        max_messages=max_messages,
        wait_time_seconds=wait_time,
        visibility_timeout=visibility_timeout,
        max_retries=max_retries,
    )

    dlq_url = os.environ.get("SQS_DLQ_URL")
    if dlq_url:
        worker.set_dead_letter_queue(dlq_url)

    return worker


if __name__ == "__main__":
    worker = create_worker_from_env()
    worker.run()